import{_ as e,c as a,o as n,d as i}from"./app.49f821a7.js";const m=JSON.parse('{"title":"Resume","description":"","frontmatter":{"layout":"doc","title":"Resume","lang":"en-US"},"headers":[{"level":2,"title":"\u{1F4BB} Experience","slug":"\u{1F4BB}-experience"},{"level":2,"title":"\u{1F393} Education","slug":"\u{1F393}-education"},{"level":2,"title":"\u{1F3AF} Skills","slug":"\u{1F3AF}-skills"},{"level":2,"title":"\u{1F4D5} Publications","slug":"\u{1F4D5}-publications"}],"relativePath":"docs/resume.md"}'),t={name:"docs/resume.md"},r=i('<h1 id="bintang-pradana-erlangga-putra" tabindex="-1">Bintang Pradana Erlangga Putra <a class="header-anchor" href="#bintang-pradana-erlangga-putra" aria-hidden="true">#</a></h1><h4 id="machine-learning-enthusiast-with-a-strong-background-in-programming" tabindex="-1">Machine learning enthusiast with a strong background in programming. <a class="header-anchor" href="#machine-learning-enthusiast-with-a-strong-background-in-programming" aria-hidden="true">#</a></h4><h6 id="bintangpradana02-gmail-com" tabindex="-1"><a href="mailto:bintangpradana02@gmail.com">bintangpradana02@gmail.com</a> <a class="header-anchor" href="#bintangpradana02-gmail-com" aria-hidden="true">#</a></h6><h2 id="\u{1F4BB}-experience" tabindex="-1">\u{1F4BB} Experience <a class="header-anchor" href="#\u{1F4BB}-experience" aria-hidden="true">#</a></h2><p><strong>Back End Engineer</strong> (May 2022 - Present, Resolv)</p><ul><li>coming soon...</li></ul><p><strong>Back End Engineer</strong> (Feb 2022 - Present, Belajar+)</p><ul><li>coming soon...</li></ul><p><strong>Lead Researcher at CvT Research Group</strong> (Jun 2021 - Feb 2022, Universitas Sebelas Maret)</p><ul><li>Led a team of researchers in developing a novel vision transformer architecture in the field of image restoration.</li></ul><p><strong>Research Assistant at CSE Research Group</strong> (May 2021 - Nov 2021, Universitas Sebelas Maret)</p><ul><li>Worked on coronary heart disease diagnosis algorithm using deep learning with cost based function.</li></ul><p><strong>Machine Learning Engineer Intern</strong> (Dec 2020 - Mar 2021, Datains)</p><ul><li>Analyzed sentiment on social media and news mentioning PT PLN.</li><li>Developed neural network architecture based on VGG16 to analyze lifestyle based on image and caption uploaded to Instagram.</li></ul><h2 id="\u{1F393}-education" tabindex="-1">\u{1F393} Education <a class="header-anchor" href="#\u{1F393}-education" aria-hidden="true">#</a></h2><p><strong>Bachelor of Science in Computer Science, Universitas Sebelas Maret</strong> (2018-2022)</p><ul><li>Research on convolutional vision transformer for image restoration.</li><li>Baccalaureate with Departmental Honors and Highest Distinction, 3.84/4.0 GPA</li></ul><h2 id="\u{1F3AF}-skills" tabindex="-1">\u{1F3AF} Skills <a class="header-anchor" href="#\u{1F3AF}-skills" aria-hidden="true">#</a></h2><p><strong>Programming:</strong> Python, SQL, TypeScript</p><p><strong>Machine Learning Tools:</strong> Pandas, Numpy, Matplotlib, Scikit-learn, Pytorch</p><h2 id="\u{1F4D5}-publications" tabindex="-1">\u{1F4D5} Publications <a class="header-anchor" href="#\u{1F4D5}-publications" aria-hidden="true">#</a></h2><p><a href="https://www.dbpia.co.kr/Journal/articleDetail?nodeId=NODE11051047" target="_blank" rel="noopener noreferrer"><strong>Hybrid Feature Selection Method Based on Genetic Algorithm for the Diagnosis of Coronary Heart Disease</strong></a> (JICCE | Mar 21, 2022)</p><ul><li>Coronary heart disease (CHD) is a comorbidity of COVID-19; therefore, routine early diagnosis is crucial. A large number of examination attributes in the context of diagnosing CHD is a distinct obstacle during the pandemic when the number of health service users is significant. The development of a precise machine learning model for diagnosis with a minimum number of examination attributes can allow examinations and healthcare actions to be undertaken quickly. This study proposes a CHD diagnosis model based on feature selection, data balancing, and ensemble-based classification methods. In the feature selection stage, a hybrid SVM-GA combined with fast correlation-based filter (FCBF) is used. The proposed system achieved an accuracy of 94.60% and area under the curve (AUC) of 97.5% when tested on the z-Alizadeh Sani dataset and used only 8 of 54 inspection attributes. In terms of performance, the proposed model can be placed in the very good category.</li></ul><p><a href="https://ieeexplore.ieee.org/document/9732972" target="_blank" rel="noopener noreferrer"><strong>The Cost-based Feature Selection Model for Coronary Heart Disease Diagnosis System Using Deep Neural Network</strong></a> (IEEE | Mar 12, 2022)</p><ul><li>The development of feature selection models in intelligence systems for the diagnosis of coronary heart disease has been widely carried out. One of the developments that have been carried out is to minimize the number of inspections carried out. Unfortunately, many features selection models do not consider the cost of inspection, so the result of feature selection is an average inspection that requires high costs. This study proposes an intelligence system model for the diagnosis of coronary heart disease using a feature selection model that considers the cost of the examination. Feature selection is developed using a genetic algorithm and support vector machine. Decision-making of the diagnosis system is carried out using a deep neural network, with system performance being measured using the parameters of accuracy, sensitivity, positive predictive value, and area under the curve (AUC). The test results use the z-Alizadeh sani model feature selection dataset which produces 5 features out of 54 existing features. The use of these 5 features is able to produce AUC performance of 93.7%, accuracy of 87.7%, and sensitivity of 87.7%. Referring to the resulting performance, it shows that the feature selection model by considering the cost of an inspection is able to provide performance in the very good category.</li></ul>',25),o=[r];function s(l,c,d,h,u,g){return n(),a("div",null,o)}var f=e(t,[["render",s]]);export{m as __pageData,f as default};
